.pagination-dots {
    height: 60px; 
    display: flex; 
    justify-content: center; 
    align-items: center; 
    gap: 4px; 
    padding-bottom: 20px;
    /* Prevent the pager from squishing the dots off-screen */
    flex-shrink: 0; 
}
.dot {
    /* Corrected dimensions for border-box */
    width: 24px; height: 24px; 
    background: #fff; border-radius: 50%; 
    /* Increased base opacity for better visibility against blur */
    opacity: 0.3; 
    cursor: pointer; 
    /* Hitbox is now the full 24px, visible dot is the 8px center */
    padding: 8px; 
    background-clip: content-box;
    transition: opacity 0.2s, transform 0.2s;
    box-sizing: border-box;
}
.dot.active { opacity: 0.9; transform: scale(1.3); }

